import React, { Component } from "react";

class Experience extends Component {
  experiencesList = [
    {
      id: 1,
      title: "Full Stack Developer",
      startDate: "August 2019",
      endDate: "current",
      companyName: "August 99 Inc. - Canstar Division",
      companyUrl: "https://www.august99.com",
      desc: ["asdasdasdasd", "asdasdasdsad", "asdasdsd"],
    },
  ];
  render() {
    return (
      <React.Fragment>
        <div className="about-container">
          <div className="row">
            <div className="col-md-12">
              <h2>Experience</h2>
            </div>
          </div>
          <div className="row experience">
            {this.experiencesList.map((exp) => (
              <div key={exp.id} className="col-md-3">
                <h4>{exp.title}</h4>
                <p>
                  {exp.startDate} - {exp.endDate}
                </p>
                <a href={exp.companyUrl}>{exp.companyName}</a>
              </div>
            ))}
          </div>
        </div>
      </React.Fragment>
    );
  }
}

export default Experience;
